using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1, Title = "Bruschetta", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Baguette slices", "Tomatoes", "Fresh basil", "Garlic", "Olive oil"],
            Steps = ["Toast baguette slices.", "Dice tomatoes and mix with basil and garlic.", "Top bread with tomato mixture and drizzle with olive oil."],
            AverageRating = 4.5, RatingCount = 12
        },
        new()
        {
            Id = 2, Title = "Stuffed Mushrooms", Category = "Appetizers", CategorySlug = "appetizers",
            Ingredients = ["Button mushrooms", "Cream cheese", "Garlic", "Parsley", "Breadcrumbs"],
            Steps = ["Remove mushroom stems.", "Mix cream cheese, garlic, and parsley.", "Fill caps and top with breadcrumbs.", "Bake at 375°F for 20 minutes."],
            AverageRating = 4.2, RatingCount = 8
        },
        new()
        {
            Id = 3, Title = "Spaghetti Carbonara", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Spaghetti", "Eggs", "Pecorino cheese", "Guanciale", "Black pepper"],
            Steps = ["Cook pasta al dente.", "Fry guanciale until crispy.", "Whisk eggs with cheese.", "Toss hot pasta with egg mixture and guanciale.", "Season with pepper."],
            AverageRating = 4.8, RatingCount = 25
        },
        new()
        {
            Id = 4, Title = "Chicken Stir-Fry", Category = "Main Courses", CategorySlug = "main-courses",
            Ingredients = ["Chicken breast", "Bell peppers", "Soy sauce", "Ginger", "Rice"],
            Steps = ["Slice chicken and vegetables.", "Stir-fry chicken until cooked.", "Add vegetables and soy sauce.", "Serve over steamed rice."],
            AverageRating = 4.0, RatingCount = 15
        },
        new()
        {
            Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour"],
            Steps = ["Melt chocolate and butter together.", "Whisk eggs and sugar.", "Fold in chocolate mixture and flour.", "Bake at 425°F for 12 minutes."],
            AverageRating = 4.9, RatingCount = 30
        },
        new()
        {
            Id = 6, Title = "Tiramisu", Category = "Desserts", CategorySlug = "desserts",
            Ingredients = ["Ladyfingers", "Mascarpone", "Espresso", "Cocoa powder", "Eggs"],
            Steps = ["Dip ladyfingers in espresso.", "Mix mascarpone with egg yolks and sugar.", "Layer soaked ladyfingers and cream.", "Refrigerate overnight and dust with cocoa."],
            AverageRating = 4.7, RatingCount = 20
        }
    ];

    private readonly Dictionary<int, List<int>> _ratings = new();

    public List<Recipe> GetByCategory(string categorySlug)
        => _recipes.Where(r => r.CategorySlug == categorySlug).ToList();

    public Recipe? GetById(int id)
        => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = [];

        _ratings[recipeId].Add(stars);

        var recipe = GetById(recipeId);
        if (recipe is not null)
        {
            recipe.RatingCount = _ratings[recipeId].Count;
            recipe.AverageRating = _ratings[recipeId].Average();
        }
    }
}

