@page "/category/{slug}"
@using RecipeCommunity.Services

@inject RecipeService RecipeService

<PageTitle>@categoryName - Recipe Community</PageTitle>

<h1>@categoryName</h1>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-link mt-3">← Back to Categories</a>

@code {
    [Parameter] public string Slug { get; set; } = string.Empty;

    private List<RecipeCommunity.Models.Recipe> recipes = [];
    private string categoryName = string.Empty;

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(Slug);
        categoryName = Slug.Replace("-", " ");
        categoryName = System.Globalization.CultureInfo.CurrentCulture.TextInfo.ToTitleCase(categoryName);
    }
}

@page "/recipe/{id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Components.Shared

@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

@if (recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <h3>Rate this Recipe</h3>
    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <a href="category/@recipe.CategorySlug" class="btn btn-link mt-3">← Back to @recipe.Category</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeCommunity.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(Id);
    }
}

@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="d-inline-flex align-items-center">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="fs-3" style="cursor: pointer; color: @(star <= currentRating ? "gold" : "#ccc")"
              @onclick="() => Rate(star)">★</span>
    }
    @if (submitted)
    {
        <span class="ms-2 text-success">Thanks! You rated @currentRating star@(currentRating != 1 ? "s" : "").</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int currentRating;
    private bool submitted;

    private void Rate(int stars)
    {
        currentRating = stars;
        submitted = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

